form:Form.form:Scripts:
		var Edit=false;
var New=false;

function xxx_adddays(strdate, cant)
{                           
	if (strdate=="") return "";
	strdate=str2date(strdate);
	strdate=date2int(strdate)+cant;

	auxdate=str2date("20000102");
	auxdate.setDate(auxdate.getDate()+strdate);

	return date2str(auxdate);
}

function RefreshControls()
{
	//Desactivo los Controles de Cambio
	if (MyHORSel==null)
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	} else 
	if (Edit)
	{
		CtrlEnabled("DATA"  , true );
		CtrlEnabled("ADD"   , false);
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , false);
		CtrlEnabled("ACCEPT", true );
		CtrlEnabled("CANCEL", true );
	} else
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , true );
		CtrlEnabled("DELETE", true );
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	}
}

function RefreshCustomSerie(MyOBJ, myserie)
{   
	var objMONTH=Ctrl("ESPERANZA_PERIODO");
	var ff, fi, now, cur, MyROW, t, d, oi_licencia, oi_horario, oi_escuadra, horDef;
	var firstDate=date2int(new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10)-1, 1));
	var lastDate =date2int(new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1));

	//Limpio el DIA
	if (myserie=="HOR")	
	{    
		MyOBJ.ClearValue("HOR");     

		for (t=0; t<Ctrl("arrHorarios").CountRow(); t++)
		{
			MyROW=Ctrl("arrHorarios").GetRow(t);

			if ((MyHORSel==null) || (MyHORSel.GetAttr("id")!=MyROW.GetAttr("id")))
			{
				fi =date2int(str2date(MyROW.GetAttr("f_fechaInicio")));
				fff=MyROW.GetAttr("f_fechaFin");
				oi_horario=MyROW.GetAttr("oi_horario");
				c=-1;
			} else
			{
				fi =date2int(str2date(Ctrl("f_fechaInicio").GetXValue()));
				fff=Ctrl("f_fechaFin").GetXValue();
				oi_horario=Ctrl("oi_horario").GetXValue();
				c=0;
			}

			if (fff=="") ff=lastDate;
		          else ff=date2int(str2date(fff))+c;
			if (ff<firstDate) continue;
			if (fi>lastDate) continue;        

			GetDataSel(MyDAT, oi_horario);
			dd=MyDAT["HOR"].arr[oi_horario];

			newval=MyOBJ.SetValue(
				"HOR",
				fi,
				ff+1,
				"Horario",
				dd.color,
				dd.color,
				"Horario "+dd.label+" desde " + int2date(fi)+((fff=="")?"":" hasta "+int2date(ff)),
				"BAR"
			);

			newval.MyID    =MyROW.GetAttr("id");
			newval.selected=MyHORSel?((MyROW.GetAttr("id")==MyHORSel.GetAttr("id"))?true:false):false;
		}       
	}

	if (myserie=="TUR")	
	{    
		MyOBJ.ClearValue("TUR");     

		arr =new Array();

		//inicializo el Array
		for (t=0; t<lastDate-firstDate; t++) arr[t]="0";

		//recorro los dias
		for (t=0; t<lastDate-firstDate; t++)
		{      

			oi_horario ="";
			oi_escuadra="";

			//obtengo el Horario
			for (d=0; d<Ctrl("arrHorarios").CountRow(); d++)
			{
				MyROW=Ctrl("arrHorarios").GetRow(d);

				if ((MyHORSel==null) || (MyHORSel.GetAttr("id")!=MyROW.GetAttr("id")))
				{
					fi =date2int(str2date(MyROW.GetAttr("f_fechaInicio")));
					ff =MyROW.GetAttr("f_fechaFin");
					if (ff=="") ff=lastDate; else ff=date2int(str2date(ff))-1;

					if (t+firstDate>=fi && t+firstDate<=ff)
					{
						oi_horario =MyROW.GetAttr("oi_horario");
						oi_escuadra=MyROW.GetAttr("oi_escuadra");
					}
				} else
				{
					fi =date2int(str2date(Ctrl("f_fechaInicio").GetXValue()));
					ff =Ctrl("f_fechaFin").GetXValue();
					if (ff=="") ff=lastDate; else ff=date2int(str2date(ff));

					if (t+firstDate>=fi && t+firstDate<=ff)
					{
						oi_horario =Ctrl("oi_horario").GetXValue();
						oi_escuadra=Ctrl("oi_escuadra").GetXValue();
						break;
					}
				}

			}                             
			if (oi_horario=="") continue; 

			//Obtengo la definicion del Horario
			horDef=MyDAT["HOR"].arr[oi_horario];

			//calculo posision
			escA=0;      
			if (oi_escuadra!="")
			{
				for (d=0; d<horDef.OPTS.Child.length; d++)
				if (oi_escuadra==horDef.OPTS.Child[d].id)
					escA=parseInt(horDef.OPTS.Child[d].avance,10);
			}
			pos=(t+firstDate+escA) % horDef.largo;     

			if (horDef.TURS.Child[pos]) arr[t]=horDef.TURS.Child[pos].tur;
		}
		arr[arr.length]="0";                    

		//dibujo
		for (d=t=0; t<arr.length; t++)
		{
			if (arr[d]!=arr[t])
			{                 
				if (arr[d]!="0")
				{
					dd=MyDAT["TUR"].arr[arr[d]];

					MyOBJ.SetValue(
						"TUR",
						firstDate+d,
						firstDate+t,
						"Turno",
						dd?dd.color:"AA0000",
						dd?dd.color:"AA0000",
						"Turno "+(dd?dd.label:"")+" desde " + int2date(d+firstDate)+" hasta "+int2date(t+firstDate)
					);
				}

				d=t;
			}
		}
	}

}

function OnClickHorario(obj, dte, value)
{               
	var MyROW;                            

	if (value.MyID?false:true) return;
	if (Edit) return;   

	MyROW=Ctrl("arrHorarios").GetRowByAttr("id", value.MyID);
	Ctrl("oi_horario"   ).SetXValue(MyROW.GetAttr("oi_horario"   ));
	Ctrl("f_fechaInicio").SetXValue(MyROW.GetAttr("f_fechaInicio"));
	Ctrl("f_fechaFin"   ).SetXValue(xxx_adddays(MyROW.GetAttr("f_fechaFin"),-1));
	Ctrl("o_horariopers").SetXValue(MyROW.GetAttr("o_horariopers"));
	SetData("HOR", MyROW.GetAttr("oi_horario"));

	MyHORSel=MyROW;

	New=false;
	ChangeHorario();
	Ctrl("oi_escuadra"  ).SetXValue(MyROW.GetAttr("oi_escuadra"  ));
}


function AddHorario()
{
	NomadTimeout("internalAddHorario();",100,"Generando el Horario...");
}   

function internalAddHorario()
{	
	var hor;
	if (Ctrl("arrHorarios").CountRow()>0)
	{	
		var MyROWHOR=Ctrl("arrHorarios").GetRow(Ctrl("arrHorarios").CountRow()-1);
		hor = MyROWHOR.GetAttr("oi_horario");
	}
	else	
		hor = MyDAT["HOR"].def.id;    		

	var newDate=new Date();
	MyROW=Ctrl("arrHorarios").AddRow();
	MyROW.SetAttr("id"            ,"#"+datetime2str(newDate));
	MyROW.SetAttr("oi_horario"    ,hor);	
	MyROW.SetAttr("oi_escuadra"   ,"");
	MyROW.SetAttr("f_fechaInicio" ,"");
	MyROW.SetAttr("f_fechaFin"    ,"");
	MyROW.SetAttr("o_horariopers" ,"");

	Ctrl("oi_horario"   ).SetXValue(MyROW.GetAttr("oi_horario"   ));
	Ctrl("oi_escuadra"  ).SetXValue(MyROW.GetAttr("oi_escuadra"  ));
	Ctrl("f_fechaInicio").SetXValue(MyROW.GetAttr("f_fechaInicio"));
	Ctrl("f_fechaFin"   ).SetXValue(xxx_adddays(MyROW.GetAttr("f_fechaFin"),-1));
	Ctrl("o_horariopers").SetXValue(MyROW.GetAttr("o_horariopers"));

	SetData("HOR", MyROW.GetAttr("oi_horario"));

	MyHORSel=MyROW;
	StartEdit();
	New=true;

	ChangeHorario();
} 


function StartEdit()
{            
	var now, cur;

	//Verifico si el rango de dias esta bloqueado
	if (MyHORSel.GetAttr("f_fechaInicio")!="")
	{
		now=NowDate();    
		var dias = Ctrl('CantidadDiasModificar').GetXValue();

		if ((NowDate()-str2date(MyHORSel.GetAttr("f_fechaInicio")))/86400000>dias)
		{
			alert("No se puede modificar.\r\nLa fecha inicial es anterior a "+dias+" dias.");
			return false;
		}

		for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
		{                                
			if (MyHORSel.GetAttr("f_fechaInicio")>cur.GetAttr("f_fin")) continue;
			if ((MyHORSel.GetAttr("f_fechaFin")!="") && (MyHORSel.GetAttr("f_fechaFin")<=cur.GetAttr("f_ini"))) continue;

			alert("No se puede modificar.\r\nExisten procesamientos cerrados en el rango de fechas.");
			return false;
		}
	}  

	Edit=true;

	MyOBJ.EditStart();           
	MyOBJ.SelectStyle("00AA00","BAR");

	RefreshControls();
}          


function EditCancel()
{         
	if (New)
	{
		Ctrl("arrHorarios").DelRowByAttr("id", MyHORSel.GetAttr("id"));
		MyHORSel=null;
	} else
	{
		Ctrl("oi_horario"   ).SetXValue(MyHORSel.GetAttr("oi_horario"   ));
		Ctrl("oi_escuadra"  ).SetXValue(MyHORSel.GetAttr("oi_escuadra"  ));
		Ctrl("f_fechaInicio").SetXValue(MyHORSel.GetAttr("f_fechaInicio"));
		Ctrl("f_fechaFin"   ).SetXValue(xxx_adddays(MyHORSel.GetAttr("f_fechaFin"),-1));
		Ctrl("o_horariopers").SetXValue(MyHORSel.GetAttr("o_horariopers"));
		SetData("HOR", MyHORSel.GetAttr("oi_horario"));
	}
	Edit=false;
	New=false;

	MyOBJ.EditEnd();          
	ReDrawWait(MyOBJ, "HOR|TUR", true, true);
}       

function ChangeTime(obj, myserie, timestart, timeend)
{                               
	if (myserie!="HOR") return;

	aux=str2date("20000102"); aux.setDate(aux.getDate()+timestart); Ctrl("f_fechaInicio").SetXValue(date2str(aux));
	aux=str2date("20000102"); aux.setDate(aux.getDate()+timeend-1); Ctrl("f_fechaFin"   ).SetXValue(date2str(aux));

	ReDrawWait(MyOBJ, "HOR|TUR", true, true);
}

function EditAccept()
{    
	var t, cur; 

    var dias = Ctrl('CantidadDiasModificar').GetXValue();

	if ((NowDate()-str2date(Ctrl("f_fechaInicio").GetXValue()))/86400000>dias)
	{
		alert("No se puede modificar.\r\nEl inicio del rango es anterior a "+dias+" dias.");       
		return false;
	}

	if (Ctrl("f_fechaInicio").GetXValue() < Ctrl("f_ingreso").GetXValue().substr(0,8))
	{
		alert("No se puede modificar.\r\nEl inicio del horario es anterior a la fecha de ingreso del legajo - " + formatdatetime2str(Ctrl("f_ingreso").GetXValue(), 'YYYYMMDD'));
		return false;
	}

	for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
	{                                
		if (Ctrl("f_fechaInicio").GetXValue()>cur.GetAttr("f_fin")) continue;
		if ((MyHORSel.GetAttr("f_fechaFin")!="") && (MyHORSel.GetAttr("f_fechaFin")<=cur.GetAttr("f_ini"))) continue;

		alert("No se puede modificar.\r\nExisten procesamientos cerrados en el rango de fechas.");
		return false;
	}


  arrDel=new Array();
  FI=Ctrl("f_fechaInicio").GetXValue();
  FF=xxx_adddays(Ctrl("f_fechaFin").GetXValue(),+1);

	for (t=0; t<Ctrl("arrHorarios").CountRow(); t++)
	{		
		MyROW=Ctrl("arrHorarios").GetRow(t);

		if (MyROW.GetAttr("id")==MyHORSel.GetAttr("id")) continue;
		if ((MyROW.GetAttr("f_fechaFin")!="") && (FI>=MyROW.GetAttr("f_fechaFin")   ))
		{		 
		 continue;
		}
		if ((FF                         !="") && (FF<=MyROW.GetAttr("f_fechaInicio")))
		{
		 continue;
		}

		if (FF=="")
		{ //caso 1: el nuevo no tiene fecha fin			
			if (MyROW.GetAttr("f_fechaInicio")>=FI)
			{ //caso 1.1: la fecha de inicio es mayor.... tiene que ser eliminado				
				arrDel.push(MyROW);
			} else
			{ //case 1.2: la fecha de inicio es menor.... cambiar la fecha de fin....				
				MyROW.SetAttr("f_fechaFin", FI);
			}
		} else
		{ //caso 2: el nuevo tiene fecha fin			
			if (MyROW.GetAttr("f_fechaInicio")>=FI)
			{ //caso 2.1: la fecha de inicio es mayor....				
				if (MyROW.GetAttr("f_fechaFin")!="" && FF>=MyROW.GetAttr("f_fechaFin"))
				{ //caso 2.1.1: la fecha de fin es Mayor.... tiene que ser eliminado					
					arrDel.push(MyROW);
				} else
				{ //caso 2.1.2: la fecha de fin es Menor.... cambiar la fecha de inicio....					
					MyROW.SetAttr("f_fechaInicio", FF); 
				}
			} else
			{ //case 2.2: la fecha de inicio es menor.... 				
				if (MyROW.GetAttr("f_fechaFin")!="" && FF>=MyROW.GetAttr("f_fechaFin"))
				{ //caso 2.2.1: la fecha de fin es Menor.... cambiar la fecha de fin....					
					MyROW.SetAttr("f_fechaFin", FI);	
				} else
				{ //caso 2.2.2: la fecha de fin es Mayor.... duplicar el registro....					
					var newDate=new Date();
					MyNEWROW=Ctrl("arrHorarios").AddRow();
					MyNEWROW.SetAttr("id"            ,"#"+datetime2str(newDate)+Ctrl("arrHorarios").CountRow());
					MyNEWROW.SetAttr("oi_horario"    ,MyROW.GetAttr("oi_horario"   ));
					MyNEWROW.SetAttr("oi_escuadra"   ,MyROW.GetAttr("oi_escuadra"  ));
					MyNEWROW.SetAttr("f_fechaInicio" ,FF);
					MyNEWROW.SetAttr("f_fechaFin"    ,MyROW.GetAttr("f_fechaFin"   ));
					MyNEWROW.SetAttr("o_horariopers" ,MyROW.GetAttr("o_horariopers"));

					MyROW.SetAttr("f_fechaFin", FI);	
				}
			}
		}
	} 

	while (MyROW=arrDel.pop())
	{
		Ctrl("arrHorarios").DelRowByAttr("id", MyROW.GetAttr("id"));
	} 

	NomadTimeout("internalEditAccept()",100,"Actualizando la Vista...");
}

function internalEditAccept()
{
	MyHORSel.SetAttr("oi_horario"   , Ctrl("oi_horario"   ).GetXValue());
	MyHORSel.SetAttr("oi_escuadra"  , Ctrl("oi_escuadra"  ).GetXValue());
	MyHORSel.SetAttr("f_fechaInicio", Ctrl("f_fechaInicio").GetXValue());
	MyHORSel.SetAttr("f_fechaFin"   , xxx_adddays(Ctrl("f_fechaFin").GetXValue(),+1));
	MyHORSel.SetAttr("o_horariopers", Ctrl("o_horariopers").GetXValue());

	Edit=false;
	New=false;

	MyOBJ.EditEnd();  
	OnChangePeriodo();
	RefreshControls();     
}



function DelHorario()
{  
	var now, maxfecha;

	//Verifico si el dia esta bloqueado 
	var dias = Ctrl('CantidadDiasModificar').GetXValue();

	if ((NowDate()-str2date(MyHORSel.GetAttr("f_fechaFin")))/86400000>=dias)
	{       
		alert("No se puede Eliminar.\r\nLa fecha final es anterior a "+dias+" dias.");
		return false;
	}

	if ((NowDate()-str2date(MyHORSel.GetAttr("f_fechaInicio")))/86400000>dias)
	{
		alert("No se puede Eliminar.\r\nExisten procesamientos cerrados en el rango de fechas.");       
		return false;
	}

	for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
	{                                
		if (Ctrl("f_fechaInicio").GetXValue()>cur.GetAttr("f_fin")) continue;
		if ((MyHORSel.GetAttr("f_fechaFin")!="") && (MyHORSel.GetAttr("f_fechaFin")<=cur.GetAttr("f_ini"))) continue;

		alert("No se puede Eliminar.\r\nExisten procesamientos cerrados en el rango de fechas.");       
		return false;
	}

	Ctrl("arrHorarios").DelRowByAttr("id", MyHORSel.GetAttr("id"));

	MyHORSel=null;
	ReDrawWait(MyOBJ, "HOR|TUR", true, true);
}


function ChangeFInicio()
{ 
	if (Ctrl("f_fechaInicio").GetXValue()=="") 
		return true;

	ReDrawWait(MyOBJ, "HOR|TUR", true, false);
}

function ChangeFFin()
{
	if (Ctrl("f_fechaFin").GetXValue()=="") 
	{
		ReDrawWait(MyOBJ, "HOR|TUR", true, false);
		return true;
	}

	ReDrawWait(MyOBJ, "HOR|TUR", true, false);
}

function ChangeEscuadra()
{
	ReDrawWait(MyOBJ, "HOR|TUR", true, false);
}

function ValidateFFin()
{
	if (Ctrl("f_fechaFin").GetXValue()!="") 
	{
		if (Ctrl("f_fechaFin").GetXValue()<Ctrl("f_fechaInicio").GetXValue())
		{                                 
			Ctrl("f_fechaFin").SetError("La 'fecha fin' tiene que ser mayor o igual a la fecha de inicio");
			return false;
		}
	}

	return true;
}

function ValidateEscuadra()
{
	if (MyDAT["HOR"].arr[Ctrl("oi_horario").GetXValue()].tipo=="R")
	{ //es rotativo
		if (Ctrl("oi_escuadra").GetXValue()=="")
		{             
			Ctrl("oi_escuadra").SetError("La escuadra es requerida en horarios Rotativos.");
			return false;
		}
	}

	return true;
}

function ChangeHorario()
{  
 	if(Ctrl("oi_horario").GetXValue()!='')
 	{
	GetDataSel(MyDAT, Ctrl("oi_horario").GetXValue());
	Ctrl("oi_escuadra").SetXValue("");
	Ctrl("oi_escuadra").SetEnabled(MyDAT["HOR"].arr[Ctrl("oi_horario").GetXValue()].tipo=="R");
	Ctrl("oi_escuadra").setOptions(MyDAT["HOR"].arr[Ctrl("oi_horario").GetXValue()].OPTS.associatedELE);
	ReDrawWait(MyOBJ, "HOR|TUR", true, true); 
	}  
	else
	{
	Ctrl("oi_escuadra").SetEnabled(false);
	}
}


function SetData(NAME, KEY)
{
	if (Ctrl("main").GetMode()!="EDIT") return;

	MyDAT[NAME].sel=KEY;     
	if (MyDAT[NAME].cont!="") DrawReference(MyDAT[NAME], MyDAT[NAME].cont);

	if ((NAME=="HOR") && (Edit))
	{
		Ctrl("oi_horario").SetXValue(MyDAT[NAME].arr[KEY].id);
		ChangeHorario();
	}
}
